        /// The currently selected tab panel.
        /// </summary>
        public MudTabPanel? ActivePanel => _activePanelIndexState.Value >= 0 && _activePanelIndexState.Value < _panels.Count ?
            _panels[_activePanelIndexState.Value] : null;

