        /// <summary>
        /// Tests that the Disabled parameter on MudTabs properly cascades to all child MudTabPanels.
        /// </summary>
        [Test]
        public async Task MudTabs_Disabled_Parameter_DisablesAllPanels()
        {
            // Render with Disabled=false
            var comp = Context.Render<TabsWithDisabledParameterTest>(parameter => parameter.Add(p => p.IsDisabled, false));

            var tabs = comp.FindComponents<MudTabPanel>();
            tabs.Should().HaveCount(3);

            // All tabs should be enabled (IsDisabled should be false)
            tabs[0].Instance.IsDisabled.Should().BeFalse();
            tabs[1].Instance.IsDisabled.Should().BeFalse();
            tabs[2].Instance.IsDisabled.Should().BeFalse();

            // All tabs should not have mud-disabled class
            var tabElements = comp.FindAll("div.mud-tab");
            tabElements.Should().HaveCount(3);
            tabElements[0].ClassList.Should().NotContain("mud-disabled");
            tabElements[1].ClassList.Should().NotContain("mud-disabled");
            tabElements[2].ClassList.Should().NotContain("mud-disabled");

            // Now set Disabled=true on MudTabs
            await comp.SetParametersAndRenderAsync(parameter => parameter.Add(p => p.IsDisabled, true));

            // All tabs should be disabled via IsDisabled (ParentDisabled cascading)
            tabs = comp.FindComponents<MudTabPanel>();
            tabs[0].Instance.IsDisabled.Should().BeTrue();
            tabs[1].Instance.IsDisabled.Should().BeTrue();
            tabs[2].Instance.IsDisabled.Should().BeTrue();

            // All tab elements should have mud-disabled class
            tabElements = comp.FindAll("div.mud-tab");
            tabElements[0].ClassList.Should().Contain("mud-disabled");
            tabElements[1].ClassList.Should().Contain("mud-disabled");
            tabElements[2].ClassList.Should().Contain("mud-disabled");

            // Should not be able to activate a disabled panel
            await comp.Instance.TabControl.ActivatePanelAsync(0);
            comp.Instance.TabControl.ActivePanelIndex.Should().Be(-1, "disabled tabs should not be activatable");
        }

        /// <summary>
        /// Tests that a panel disabled individually remains disabled even when the parent MudTabs is not disabled.
        /// </summary>
        [Test]
        public async Task MudTabs_IndividualPanelDisabled_WhenParentDisabled_CorrectState()
        {
            var comp = Context.Render<TabsWithDisabledParameterTest>(parameter =>
            {
                parameter.Add(p => p.IsDisabled, true);
                parameter.Add(p => p.IsTab3Disabled, true);
            });

            var tabs = comp.FindComponents<MudTabPanel>();
            tabs.Should().HaveCount(3);

            // All panels should be IsDisabled due to parent
            tabs[0].Instance.IsDisabled.Should().BeTrue();
            tabs[1].Instance.IsDisabled.Should().BeTrue();
            tabs[2].Instance.IsDisabled.Should().BeTrue();

            // Now disable parent disabled state
            await comp.SetParametersAndRenderAsync(parameter => parameter.Add(p => p.IsDisabled, false));

            // Tab 1 and 2 should now be enabled, Tab 3 should still be disabled (individually)
            tabs = comp.FindComponents<MudTabPanel>();
            tabs[0].Instance.IsDisabled.Should().BeFalse();
            tabs[1].Instance.IsDisabled.Should().BeFalse();
            tabs[2].Instance.IsDisabled.Should().BeTrue("Tab 3 should remain individually disabled");

            // Verify CSS classes
            var tabElements = comp.FindAll("div.mud-tab");
            tabElements[0].ClassList.Should().NotContain("mud-disabled");
            tabElements[1].ClassList.Should().NotContain("mud-disabled");
            tabElements[2].ClassList.Should().Contain("mud-disabled");
        }
    }
}

